import React, { useCallback, useEffect, useRef } from 'react'
import { useCountdownStore } from './useCountDownStore'

const playTick = () => {
    const ctx = new AudioContext()
    const oscillator = ctx.createOscillator()
    const gainNode = ctx.createGain()

    oscillator.connect(gainNode)
    gainNode.connect(ctx.destination)

    oscillator.frequency.value = 1000
    gainNode.gain.setValueAtTime(0.1, ctx.currentTime)
    gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1)

    oscillator.start(ctx.currentTime)
    oscillator.stop(ctx.currentTime + 0.1)
}

function useCountdown() {
    const { initialSeconds, setIsRunning, setTimeLeft, timeLeft } = useCountdownStore((state) => state)
    const intervalRef = useRef(null)

    const start = (timeLeft) => {
        setIsRunning(true)
        if (timeLeft <= 0 && intervalRef.current != null) {
            clearInterval(intervalRef.current)
            intervalRef.current = null
            setIsRunning(false)
            setTimeLeft(0)
        } else {
            const newTimeLeft = timeLeft - 1
            setTimeLeft(newTimeLeft)
            intervalRef.current = setTimeout((value) => {
                start(value)
            }, 1000, newTimeLeft)

        }
    }

    const pause = useCallback(() => {
        clearInterval(intervalRef.current)
        intervalRef.current = null
        setIsRunning(false)
    }, [])

    const reset = useCallback(() => {
        clearInterval(intervalRef.current)
        intervalRef.current = null
        setIsRunning(false)
        setTimeLeft(initialSeconds)
    }, [initialSeconds])

    return { start, pause, reset }
}

export default useCountdown
